import numpy as np
from scipy.optimize import curve_fit

def lorentzian(x, g, m):
    return m**2 / (1.0 + (x/g)**2)

def gauss(x, s, a):
    return a*np.exp(-0.5*(x/s)**2)

def harmonic_mask(lags, spacing, halfwidth):
    """True=keep; drop lags near k*spacing (k>=1). Zero-lag neighbourhood kept."""
    d = np.abs(np.abs(lags) - np.round(np.abs(lags)/spacing)*spacing)
    near = (d <= halfwidth) & (np.abs(lags) >= 0.5*spacing)
    return ~near

def estimate_peak_halfwidth(lags, acf, chan_width, exclude_ch=1.0, search_max=None):
    """1/e half-width of the central peak AFTER excluding the zero-lag self-noise bins."""
    order=np.argsort(lags); L=lags[order]; A=acf[order]
    pos = L > exclude_ch*chan_width
    if search_max: pos &= (L <= search_max)
    Lp, Ap = L[pos], A[pos]
    if len(Lp) < 3: return None
    a0 = Ap[0]  # value just outside the self-noise bin
    if a0 <= 0: return None
    thr = a0/np.e
    for j in range(1, len(Lp)):
        if Ap[j] < thr or Ap[j] < 0:
            return Lp[j-1] + (Lp[j]-Lp[j-1])*(Ap[j-1]-thr)/max(Ap[j-1]-Ap[j],1e-9)
    return Lp[-1]

def fit_scintle(lags, acf, chan_width, band, ripple_spacing=0.390625):
    """Corrected fit: exclude self-noise bin, auto window, narrow+broad, optional comb mask."""
    order=np.argsort(lags); L=lags[order]; A=acf[order]
    # measure peak half-width (self-noise excluded)
    hw = estimate_peak_halfwidth(L, A, chan_width, exclude_ch=1.0,
                                 search_max=(20 if band=="dsa" else 3))
    if hw is None or hw <= 0:
        return None
    win = min(max(8*hw, 10*chan_width), (L.max()))  # auto window: ~8x half-width
    # build fit mask: positive lags, within window, exclude innermost self-noise bin
    m = (L > 1.0*chan_width) & (L <= win)
    if band=="chime":
        m &= harmonic_mask(L, ripple_spacing, halfwidth=0.12)  # widened comb mask
    x, y = L[m], A[m]
    if len(x) < 8: return None
    a0 = y[0]
    # narrow+broad two-Lorentzian; report narrow
    def two_lor(xx, g1, m1, g2, m2, c):
        return lorentzian(xx,g1,m1)+lorentzian(xx,g2,m2)+c
    try:
        p,pc=curve_fit(two_lor, x, y, p0=[hw, np.sqrt(a0), 5*hw, np.sqrt(a0/2), 0],
